// AddTimberOwnerContactModal for FPA Aerial Chemical Application
// Business or Individual
const businessOrindividual = VV.Form.GetFieldValue('Timber Owner Business Or Individual');
let term;
let addButtonName;
let helpText;

// Determine the signer type
if (businessOrindividual === 'Business') {
  term = 'Business Signer';
  addButtonName = 'Select Business';
  helpText = `Please select one of the business records below and click 'Select Business' to associate a business with this application. Note: To make changes to your Business record (e.g., mailing address) please contact your local region office. This can be done before or after you have submitted your application`
} else if (businessOrindividual === 'Individual') {
  term = 'Timber Owner';
  addButtonName = 'Select Contact'
  helpText = `Please select one of the contact records below and click 'Select Contact' to associate a contact as a Timber Owner with this application. Note: To make changes to your contact record (e.g., mailing address) please contact your local region office. This can be done before or after you have submitted your application.`
} else {
  // Display error message and stop execution
  VV.Form.Global.DisplayModal({
    Icon: 'error',
    Title: 'Selection Required',
    HtmlContent: 'Please select a Business or Individual from the Business Individual dropdown.',
  });
  return; // Stop further execution
}

// Function to display the "Select Contact" modal
function showSelectContactModal() {
  const recordHtmlArray = recordsArray
    .map(
      (record) => `
        <tr class="record-row">
          <td>${record["first Name"] || "N/A"}</td>
          <td>${record["last Name"] || "N/A"}</td>
          <td>${record["address Line 1"] || "N/A"}</td>
          <td>${record["city"] || "N/A"}</td>
          <td>${record["state"] == 'Select Item' && !record["province"] ? 'N/A' : record["country"] == "United States" ? record["state"] : record["province"]}</td>
          <td>${record["zip Code"] || "N/A"}</td>
          <td>${record["phone"] || "N/A"}</td>
          <td>
            <button class="k-button add-btn" data-formid="${record["contact Information ID"]}">
              ${addButtonName}
            </button>
          </td>
        </tr>
      `
    )
    .join("");

  const recordHtml = `
    <p>
      ${helpText}
    </p>
    <div class="records-container">
      <table class="record-table">
        <thead>
          <tr>
            <th>First Name</th>
            <th>Last Name</th>
            <th>Address</th>
            <th>City</th>
            <th>State/Province</th>
            <th>Postal/Zip Code</th>
            <th>Phone</th>
            <th></th>
          </tr>
        </thead>
        <tbody>${recordHtmlArray}</tbody>
      </table>
    </div>
  `;

  Swal.fire({
    icon: "info",
    title: `${term} Search`,
    html: recordHtml,
    width: "70rem", // Adjust modal width
    showConfirmButton: addNewContactButton,
    confirmButtonText: 'Add New Contact',
    showCancelButton: true,
    cancelButtonText: "Close Search",
    allowOutsideClick: false,
    didRender: () => {
      // Apply styles after rendering
      $(".records-container").css({
        "max-height": "320px",
        "overflow-y": "auto",
        "overflow-x": "auto",
      });

      $(".record-table").css({
        width: "100%",
        "border-collapse": "collapse",
      });

      $(".record-table th, .record-table td").css({
        padding: "8px",
        "border": "1px solid #333",
        "text-align": "center",
      });

      $(".record-row:nth-child(odd)").css({
        "background-color": "#f9f9f9",
      });

      $(".record-row:nth-child(even)").css({
        "background-color": "white",
      });

      // Add click event to buttons
      $(".add-btn")
        .off("click")
        .on("click", function () {
          const formID = $(this).data("formid");
          const selectedRecord = recordsArray.find(
            (record) => record["contact Information ID"] === formID
          );

          if(businessOrindividual === "Business"){
            showAssociateBusinessModal(selectedRecord); //Go to "Associate Business" modal
          }else{
            showAddContactModal(selectedRecord); // Go to "Add Contact" modal
          }          
        });
    },
  }).then((result) => {
    if (result.isDismissed) {
      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    } else if (result.isConfirmed) {
        // Create a new object with the Timber Owner details
        const timberOwner = {
            firstName: VV.Form.GetFieldValue("Timber Owner Search First Name"),
            lastName: VV.Form.GetFieldValue("Timber Owner Search Last Name"),
            country: VV.Form.GetFieldValue("Timber Owner Search Country"),
            postalZipCode: VV.Form.GetFieldValue("Timber Owner Search Postal Zip Code"),
            addressLine1: VV.Form.GetFieldValue("Timber Owner Search Address Line 1"),
            addressLine2: VV.Form.GetFieldValue("Timber Owner Search Address Line 2"),
            addressLine3: VV.Form.GetFieldValue("Timber Owner Search Address Line 3"),
            city: VV.Form.GetFieldValue("Timber Owner Search City"),
            provinceState: VV.Form.GetFieldValue("Timber Owner Search Province State"),
            county: VV.Form.GetFieldValue("Timber Owner Search County"),
            phone: VV.Form.GetFieldValue("Timber Owner Search Phone"),
            email: VV.Form.GetFieldValue("Timber Owner Search Email"),
        };
        // Pass the object to the AddTimber OwnerContact function
        VV.Form.Template.AddTimberOwnerContact(timberOwner);
    }
  });
}

// Function to display the "Associate Business" modal
function showAssociateBusinessModal(selectedRecord) {
  //Use query to get all Business records already associated
  VV.Form.Global.UseCustomQuery(
    "zClientSideGetAssociatedBusiness",
    VV.Form.GetFieldValue("Form ID"),
    `[Business Name] <> '${Math.random()}'`
  ).then((response) => {

    const recordHtmlArray = response.map(record => `
      <tr class="record-row">
        <td>${record["business Name"] || 'N/A'}</td>
        <td>${record["business ID Number"] || 'N/A'}</td>
        <td>${record["business Address Line 1"] || 'N/A'}</td>
        <td>${record["business City"] || 'N/A'}</td>
        <td>${record["business Province State"] || 'N/A'}</td>
        <td>${record["business Zip Code"] || 'N/A'}</td>
        <td>${record["business Country"] || 'N/A'}</td>
        <td><button class="k-button ng-star-inserted add-btn" data-formid="${record["business ID"]}" data-businessname="${record["business Name"]}">Select Business</button></td>
      </tr>
    `).join("");

    // Complete HTML structure for the modal, including table headers and rows
    const associateHtml = `
    <p style="text-align: left; line-height: 1.6;">You are adding this contact as a Business Signer. To continue, please select a business from the list below and click
    'Select Business' to associate it with the contact.</p>
    <div class="records-container">
      <table class="record-table">
        <thead>
          <tr>
            <th>Business Name</th>
            <th>ID Number</th>
            <th>Address</th>
            <th>City</th>
            <th>State/Province</th>
            <th>Postal/Zip Code</th>
            <th>Country</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          ${recordHtmlArray}
        </tbody>
      </table>
    </div>
  `;

    Swal.fire({
      icon: "info",
      title: `${term} Search`,
      html: associateHtml,
      showCancelButton: true,
      showConfirmButton: true,
      showDenyButton: false,
      allowOutsideClick: false,
      confirmButtonText: "Back",
      //denyButtonText: "Next",
      cancelButtonText: "Close Search",
      width: "70rem", // Modal width
      customClass: {
        confirmButton: "blue-button back-button",
        //denyButton: "blue-button next-button",
        cancelButton: "blue-button cancel-button",
      },
      didRender: () => {
        // Rearrange buttons
        const actions = Swal.getActions(); // Get the actions container
        const confirmButton = Swal.getConfirmButton(); // Back button
        const cancelButton = Swal.getCancelButton(); // Close Search button

        // Set custom order using flexbox order property
        confirmButton.style.order = 1; // Back button
        cancelButton.style.order = 2;  // Cancel button

        // Ensure the actions container uses flexbox
        actions.style.display = 'flex';

        // Directly modify the deny button style after rendering
        $(".swal2-deny").css({
          "background-color": $(".swal2-confirm").css("background-color"),
          "color": $(".swal2-confirm").css("color"),
        });
      },
    }).then((result) => {
      if (result.isConfirmed) {
        showSelectContactModal(); // Go back to the "Select Contact" modal
      } else if (result.isDismissed) {
        // Close modal
        // Call clearFieldsCallback when modal is closed or canceled
        clearFieldsCallback();
      }
    });

    // Style adjustments for the modal content
    $(".records-container").css({
      "max-height": "320px",
      "overflow-y": "auto",
      "overflow-x": "hidden",
    });

    $(".record-table").css({
      width: "100%",
      "border-collapse": "collapse",
    });

    $(".record-table th, .record-table td").css({
      padding: "8px",
      "border": "1px solid #333",
      "text-align": "center",
    });

    $(".record-row:nth-child(odd)").css({
      "background-color": "#f9f9f9",
    });

    $(".record-row:nth-child(even)").css({
      "background-color": "white",
    });

    // Rebind the click event to each "Add Business" button
    $(".add-btn").off("click").on("click", function () {
      const formID = $(this).data("formid");
      const businessName = $(this).data("businessname");

      selectedRecord["business ID"] = formID;
      selectedRecord["business Name"] = businessName;

      showAddContactModal(selectedRecord); // Go to "Add Contact" modal
    });

  });
}

// Function to display the "Add Contact" modal
function showAddContactModal(record) {
  const addContactHtml = `
    <div style="text-align: left; line-height: 1.6;">
      <p>Are you sure you want to associate the selected contact as ${(term === 'Timber Owner') ? "Timber Owner" : "Business Signer"}?</p>
      <p><strong>${term}:</strong> ${record["first Name"]} ${record["last Name"]}</p>
      ${(term === 'Business Signer') ? `<p><strong>Timber Owner:</strong> ${record["business Name"]}</p>` : ''}
    </div>
  `;

  Swal.fire({
    icon: "question",
    title: (term === 'Timber Owner') ? "Add Timber Owner" : "Add Business Signer",
    html: addContactHtml,
    showCancelButton: true,
    showConfirmButton: true,
    showDenyButton: true,
    allowOutsideClick: false,
    confirmButtonText: "Back",
    denyButtonText: (term === 'Timber Owner') ? "Add Timber Owner" : "Add Business Signer",
    cancelButtonText: "Cancel",
    width: "40rem", // Modal width for Add Contact
    didRender: () => {
      // Rearrange buttons
      const actions = Swal.getActions(); // Get the actions container
      const confirmButton = Swal.getConfirmButton(); // Back button
      const denyButton = Swal.getDenyButton(); // Add Contact button
      const cancelButton = Swal.getCancelButton(); // Cancel button

      // Set custom order using flexbox order property
      confirmButton.style.order = 1; // Back button
      denyButton.style.order = 2;    // Add Contact button
      cancelButton.style.order = 3;  // Cancel button

      // Directly modify the deny button style after rendering
      $(".swal2-deny").css({
        "background-color": $(".swal2-confirm").css("background-color"),
        "color": $(".swal2-confirm").css("color"),
      });

      // Ensure the actions container uses flexbox
      actions.style.display = 'flex';
    },
  }).then((result) => {
    if (result.isConfirmed) {
      // Go back to Selec Contact Modal
      showSelectContactModal();

    } else if (result.isDenied) {
        // Perform the action to add the contact
        console.log("Contact Information ID:", record["contact Information ID"]);
        console.log("Contact Name:", `${record["first Name"]} ${record["last Name"]}`);

        // Call the callback function to handle adding the contact
        VV.Form.DoAjaxFormSave().then(() => {
          addTimberOwnerCallback(
            record["contact Information ID"], 
            record["first Name"],
            record["last Name"],
            null, 
            null, 
            record["business ID"]);
        })

    } else if (result.isDismissed) {
      // Clear fields if modal is dismissed via Cancel button
      clearFieldsCallback();
    }
  });
}

