// HandleNavigation for Forest Practices Aerial Chemical Application Notification
/**
 * @param targetDirection - {string} Allowed values: Set | Next | Back
 * @returns Promise
 */

const ALLOWED_DIRECTIONS = ['Set', 'Next', 'Back'];
if (!ALLOWED_DIRECTIONS.includes(targetDirection)) {
  console.error('Not allowed navigation param.');
  return;
}

const sortKeys = (a, b) => {
  const isA1x = a.startsWith('1');
  const isB1x = b.startsWith('1');

  if (isA1x && isB1x) return a.localeCompare(b);
  if (isA1x) return -1;
  if (isB1x) return 1;

  return (parseInt(a) || 0) - (parseInt(b) || 0);
};

const NAVIGATION_MAP = VV.Form.Template.GetNavigationMap();

const currentScreen = VV.Form.GetFieldValue('Current Screen');

function getTargetScreen(currentScreen, targetDirection) {
  const keys = Object.keys(NAVIGATION_MAP).sort(sortKeys); // Get all keys sorted
  const index = keys.indexOf(currentScreen); // Find the index of the current key

  const isNext = targetDirection === 'Next';
  const isBack = targetDirection === 'Back';

  const invalidDirection = !isNext && !isBack;

  const indexNotFound = index === -1;
  const backNotAllowed = isBack && index === 0;
  const nextNotAllowed = isNext && index === keys.length - 1;

  if (indexNotFound || backNotAllowed || nextNotAllowed || invalidDirection) {
    console.error('Error getting target screen.');
    return null;
  }

  const targetIndex = isNext ? index + 1 : index - 1;
  return keys[targetIndex];
}

function saveProgress() {
  return VV.Form.DoAjaxFormSave();
}

if (targetDirection === 'Set') {
  const targetSetScreen = currentScreen != '' ? currentScreen : '1a';
  VV.Form.Template.SetProgressText(targetSetScreen);
  return VV.Form.Template.SetButtonVisibility(targetSetScreen);
} else {
  const targetScreen = getTargetScreen(currentScreen, targetDirection);
  VV.Form.Template.SetProgressText(targetScreen);
  const currentDropdownVal = `${targetScreen}. ${NAVIGATION_MAP[targetScreen].text}`;
  return VV.Form.Template.SetButtonVisibility(targetScreen)
    .then(() => VV.Form.SetFieldValue('Current Screen', targetScreen))
    .then(() => VV.Form.SetFieldValue('List Of Questions', currentDropdownVal))
    .then(saveProgress)
    .catch((error) => {
      console.log('An error ocurred during navigation.', error);
    });
}

// CallLibSignatureSendNotifications for Forest Practices Aerial Chemical Application Notification
const websvcName = 'LibSignatureSendNotifications';

const deferred = $.Deferred();
const CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  // Create the form data to send to the microservice
  const formData = [
    {
      name: 'Related Record ID',
      value: VV.Form.DhDocID,
    },
  ];

  // Convert form data to JSON and prepare the server-side call
  const data = JSON.stringify(formData);
  const requestObject = $.ajax({
    type: 'POST',
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  let messageData = '';
  let resolvePromise = false;
  let callData = {};
  if (typeof resp.status != 'undefined') {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != 'undefined') {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == '200') {
    if (resp.data[0] !== 'undefined') {
      if (resp.data[0] === 'Success') {
        resolvePromise = true;
        callData = resp.data[2]
      } else if (resp.data[0] === 'Error') {
        messageData = `An error was encountered. ${resp.data[1]}`;
        displayErrorModal(messageData);
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        displayErrorModal(messageData);
      }
    } else {
      messageData = 'The status of the response returned as undefined.';
      displayErrorModal(messageData);
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    displayErrorModal(messageData);
  }
  // resolve/reject promise
  if (resolvePromise) {
    deferred.resolve(callData);
  } else {
    deferred.reject(messageData);
  }
});

function displayErrorModal(messageData) {
  VV.Form.Global.DisplayModal({
    Title: 'Error',
    Icon: 'error',
    HtmlContent: messageData,
  });
}

return deferred.promise();

