// Display error modal
function displayErrorModal(messageData) {
  const unableText = `Unable to add ${label}`;
  let icon = "error";
  if (messageData.includes("Duplicate")) {
    icon = "warning";
    messageData = `Duplicate Found: The selected ${label} is already associated with this application.`;
  }
  VV.Form.Global.DisplayModal({
    Title: unableText,
    Icon: icon,
    HtmlContent: messageData,
  });
}

