/*
    Script Name:   AddBusinessRecordModal
    Customer:      WADNR
    Purpose:       This process creates a central modal for selecting and adding a business record to the current form.

    Parameters:   records[] - array of objects, each with relevant business fields (text, form ID, etc.)
                  addBusinessRecordCallback - the function to call when clicking the add button
                  clearFieldsCallback - the function to call when closing the modal
                  role - choice between Landowner, Timber Owner, and Operator
                  prefix - the prefix for the business search fields
                  includeAddBusinessButton - boolean to determine if the "Add New Business" button should be included
    Date of Dev:   10/29/2024
    Last Rev Date: 02/04/2025
    Revision Notes:
    10/29/2024 - Brian Davis : Initial creation for business records.
    02/04/2025 - Austin Stone : added role parameter
    11/03/2025 - Sebastian Rolando: Update confirmation Modal and text content for buttons
*/

// Determine the modal message based on the number of records
const recordCount = records.length;

// Generate HTML table rows for each business record
const recordHtmlArray = records.map(record => `
  <tr class="record-row">
    <td>${record["business Name"] || 'N/A'}</td>
    <td>${record["business ID Number"] || 'N/A'}</td>
    <td>${record["business Address Line 1"] || 'N/A'}</td>
    <td>${record["business City"] || 'N/A'}</td>
    <td>${record["business Province State"] || 'N/A'}</td>
    <td>${record["business Zip Code"] || 'N/A'}</td>
    <td>${record["business Country"] || 'N/A'}</td>
    <td><button class="k-button ng-star-inserted add-btn" data-formid="${record["business ID"]}" data-businessname="${record["business Name"]}">Select Business</button></td>
  </tr>
`).join("");

// Complete HTML structure for the modal, including table headers and rows
const recordHtml = `
  <p>Please select one of the business records below and click 'Select Business' to associate a business as a ${role} with this application. Note: To make changes to your Business record (e.g., mailing address) please contact your local region office. This can be done before or after you have submitted your application</p>
  <div class="records-container" style="overflow-x: auto;">
    <table class="record-table">
      <thead>
        <tr>
          <th>Business Name</th>
          <th>ID Number</th>
          <th>Address</th>
          <th>City</th>
          <th>State/Province</th>
          <th>Postal/Zip Code</th>
          <th>Country</th>
          <th></th>
        </tr>
      </thead>
      <tbody>
        ${recordHtmlArray}
      </tbody>
    </table>
  </div>
`;

// Function to display the initial search results modal
function showSearchResultsModal() {


  Swal.fire({
    icon: "info",
    title: `Select Business`,
    html: recordHtml,
    width: "70rem",
    showCancelButton: true,
    showConfirmButton: includeAddBusinessButton,
    confirmButtonText: 'Add New Business',
    cancelButtonText: "Close Search",
  }).then(result => {
    if (result.isDismissed) {
      clearFieldsCallback();
    } else if (result.isConfirmed) {

      const business = {
        businessName: VV.Form.GetFieldValue(`${prefix} Business Name`),
        businessCountry: VV.Form.GetFieldValue(`${prefix} Country`),
        businessZipCode: VV.Form.GetFieldValue(`${prefix} Postal Zip Code`),
        businessAddressLine1: VV.Form.GetFieldValue(`${prefix} Address Line 1`),
        businessAddressLine2: VV.Form.GetFieldValue(`${prefix} Address Line 2`),
        businessAddressLine3: VV.Form.GetFieldValue(`${prefix} Address Line 3`),
        businessCity: VV.Form.GetFieldValue(`${prefix} City`),
        businessProvinceState: VV.Form.GetFieldValue(`${prefix} Province State`),
        businessCounty: VV.Form.GetFieldValue(`${prefix} County`),
        businessPhone: VV.Form.GetFieldValue(`${prefix} Phone`),
        businessEmail: VV.Form.GetFieldValue(`${prefix} Email`),
        role: role
      };

      VV.Form.Template.AddNewBusiness(business);

    }
  });

  // Style adjustments for the modal content
  $(".records-container").css({
    "max-height": "320px",
    "overflow-y": "auto",
    "overflow-x": "auto"
  });

  $(".record-table").css({
    width: "100%",
    "border-collapse": "collapse",
  });

  $(".record-table th, .record-table td").css({
    padding: "8px",
    "border": "1px solid #333",
    "text-align": "center",
  });

  $(".record-row:nth-child(odd)").css({
    "background-color": "#f9f9f9",
  });

  $(".record-row:nth-child(even)").css({
    "background-color": "white",
  });

  // Rebind the click event to each "Add Business" button
  $(".add-btn").off("click").on("click", function () {
    const formID = $(this).data("formid");
    const businessName = $(this).data("businessname");

    // Handle decision functions
    const addLandownerFunction = () => {
      VV.Form.DoAjaxFormSave().then(() => {
        addBusinessRecordCallback(formID, businessName, role);
      });
    };

    const backToResultModalFunction = () => {
      // Re-display the search results modal if "Cancel" is clicked
      showSearchResultsModal();
    }

    const dismissedFunction = () => {
      clearFieldsCallback();
    }


    // Display confirmation modal for adding the selected business, including the business name
    VV.Form.Global.DisplayModal(
      {
        Icon: 'question',
        Title: `Add ${role}`,
        HtmlContent: `
                Are you sure you want to associate the selected business as a ${role}?<br><br><b>Business Name:</b> ${businessName}
        `,
        okFunction: backToResultModalFunction,
        secondFunction: addLandownerFunction,
        dismissFunction: dismissedFunction,
        SecondaryText: `Add ${role}`,
        ConfirmText: 'Back'
      }
    )
  });
}

// Initial call to display the search results modal
showSearchResultsModal();

