// Generate dropdown options for the 'Same As' modal
const dropdownOptions = `
  <option value="">Select</option>
  <option value="Yes">Yes</option>
  <option value="No">No</option>
`;

// Function to display the "Same As" modal
function showSameAsModal(selectedBusinessId, selectedBusinessName) {
  // Retrieve saved selections from session storage
  const savedRole1SameAs = sessionStorage.getItem('role1SameAs') || '';
  const savedRole2SameAs = sessionStorage.getItem('role2SameAs') || '';

  const sameAsHtml = `
  <p style="text-align: left; line-height: 1.6;">Please answer the following questions before adding the contact:</p>
  <div style="display: flex; flex-direction: column; gap: 1rem; padding: 1rem 0;">
    <div style="display: flex; align-items: center; gap: 1rem; width: 100%;">
      <label for="role1SameAs" style="flex: 1 0 50%; text-align: left; white-space: nowrap;">
        Is the ${role1} the same as the ${mainRole}?
      </label>
      <select id="role1SameAs" style="flex: 1 0 25%; padding: 0.3rem;">${dropdownOptions}</select>
    </div>
    <div style="display: flex; align-items: center; gap: 1rem; width: 100%;">
      <label for="role2SameAs" style="flex: 1 0 50%; text-align: left; white-space: nowrap;">
        Is the ${role2} the same as the ${mainRole}?
      </label>
      <select id="role2SameAs" style="flex: 1 0 25%; padding: 0.3rem;">${dropdownOptions}</select>
    </div>
  </div>
`;

  Swal.fire({
    icon: 'question',
    title: `Same as ${mainRole}?`,
    html: sameAsHtml,
    showCancelButton: true,
    showConfirmButton: true,
    showDenyButton: true,
    allowOutsideClick: false,
    confirmButtonText: 'Back',
    denyButtonText: 'Next',
    cancelButtonText: 'Cancel',
    width: '50rem', // Modal width
    customClass: {
      confirmButton: 'blue-button back-button',
      denyButton: 'blue-button next-button',
      cancelButton: 'blue-button cancel-button',
    },
    preDeny: () => {
      const role1Value = document.getElementById('role1SameAs').value;
      const role2Value = document.getElementById('role2SameAs').value;

      if (!role1Value || !role2Value) {
        Swal.showValidationMessage(`The 'Same As ${mainRole}' questions must be answered.`);
        return false;
      }

      // Save selections to session storage
      sessionStorage.setItem('role1SameAs', role1Value);
      sessionStorage.setItem('role2SameAs', role2Value);

      return { role1SameAs: role1Value, role2SameAs: role2Value };
    },
    didRender: () => {
      // Rearrange buttons
      const actions = Swal.getActions(); // Get the actions container
      const confirmButton = Swal.getConfirmButton(); // Back button
      const denyButton = Swal.getDenyButton(); // Next button
      const cancelButton = Swal.getCancelButton(); // Cancel button

      // Set custom order using flexbox order property
      confirmButton.style.order = 1; // Back button
      denyButton.style.order = 2; // Next button
      cancelButton.style.order = 3; // Cancel button

      // Ensure the actions container uses flexbox
      actions.style.display = 'flex';

      // Directly modify the deny button style after rendering
      $('.swal2-deny').css({
        'background-color': $('.swal2-confirm').css('background-color'),
        color: $('.swal2-confirm').css('color'),
      });

      // Set the dropdowns to saved values if available
      document.getElementById('role1SameAs').value = savedRole1SameAs;
      document.getElementById('role2SameAs').value = savedRole2SameAs;
    },
  }).then((result) => {
    if (result.isConfirmed) {
      if(isBusinessSigner) {
        showAssociateBusinessModal();
      }else{
        showSearchResultsModal(); // Go back to the "Select Contact" modal
      }      
    } else if (result.isDenied) {
      const { role1SameAs, role2SameAs } = result.value;
      // Proceed to Add Contact modal, pass the record and same as values
      showAddContactModal(role1SameAs, role2SameAs, selectedBusinessId, selectedBusinessName); // Call the "Add Contact" modal
    } else if (result.isDismissed) {
      // Clear selections if modal is dismissed via Cancel button
      sessionStorage.removeItem('role1SameAs');
      sessionStorage.removeItem('role2SameAs');

      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    }
  });
}

// Function to display the "Add Contact" modal
function showAddContactModal(role1SameAs, role2SameAs, selectedBusinessId, selectedBusinessName) {
  let addContactHtml;

  if(!isBusinessSigner){
    addContactHtml = `
    <div style="text-align: left; line-height: 1.6;">
      <p>Are you sure you want to associate the selected contact as a ${mainRole}?</p>
      <p><strong>Name:</strong> ${selectedContactFirstName} ${selectedContactLastName}</p>
      <p style='display: ${role === 'Landowner' ? 'absolut' : 'none'}'><strong>${mainRole} same as ${role1}:</strong> ${role1SameAs}</p>
      <p style='display: ${role === 'Landowner' ? 'absolut' : 'none'}'><strong>${mainRole} same as ${role2}:</strong> ${role2SameAs}</p>
    </div>
  `;
  }else{    
    addContactHtml = `
    <div style="text-align: left; line-height: 1.6;">
      <p>Are you sure you want to associate the selected contact as a Business Signer?</p>
      <p><strong>Business Signer:</strong> ${selectedContactFirstName} ${selectedContactLastName}</p>
      <p><strong>${mainRole}:</strong> ${selectedBusinessName}</p>
      <p style='display: ${role === 'Landowner' ? 'absolut' : 'none'}'><strong>${mainRole} same as ${role1}:</strong> ${role1SameAs}</p>
      <p style='display: ${role === 'Landowner' ? 'absolut' : 'none'}'><strong>${mainRole} same as ${role2}:</strong> ${role2SameAs}</p>
    </div>
  `;
  }

  Swal.fire({
    icon: 'question',
    title: `Add ${isBusinessSigner ? 'Business Signer' : mainRole}`,
    html: addContactHtml,
    showCancelButton: true,
    showConfirmButton: true,
    showDenyButton: true,
    allowOutsideClick: false,
    confirmButtonText: 'Back',
    denyButtonText: `Add ${isBusinessSigner ? 'Business Signer' : mainRole}`,
    cancelButtonText: 'Cancel',
    width: '40rem', // Modal width for Add Contact
    didRender: () => {
      // Rearrange buttons
      const actions = Swal.getActions(); // Get the actions container
      const confirmButton = Swal.getConfirmButton(); // Back button
      const denyButton = Swal.getDenyButton(); // Add Contact button
      const cancelButton = Swal.getCancelButton(); // Cancel button

      // Set custom order using flexbox order property
      confirmButton.style.order = 1; // Back button
      denyButton.style.order = 2; // Add Contact button
      cancelButton.style.order = 3; // Cancel button

      // Directly modify the deny button style after rendering
      $('.swal2-deny').css({
        'background-color': $('.swal2-confirm').css('background-color'),
        color: $('.swal2-confirm').css('color'),
      });

      // Ensure the actions container uses flexbox
      actions.style.display = 'flex';
    },
  }).then((result) => {
    if (result.isConfirmed) {
      if(role === "Landowner"){
        showSameAsModal(selectedBusinessId, selectedBusinessName); // Go back to the "Same As" modal
      } else {
        if(isBusinessSigner) {
          showAssociateBusinessModal(); // Go to "Associate Business" modal
        } else {
          showSearchResultsModal(); // Go back to the "Select Contact" modal
        }
      }
    } else if (result.isDenied) {
      // Clear selections when contact is added
      sessionStorage.removeItem('role1SameAs');
      sessionStorage.removeItem('role2SameAs');

      VV.Form.DoAjaxFormSave().then(() => {
        addSelectedContact(
          selectedContactId,
          role1SameAs,
          role2SameAs,
          selectedBusinessId
        );
      });
    } else if (result.isDismissed) {
      // Clear selections if modal is dismissed via Cancel button
      sessionStorage.removeItem('role1SameAs');
      sessionStorage.removeItem('role2SameAs');

      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    }
  });
}

// Callback function to add the selected contact record and other params
function addSelectedContact(contactId, role1SameAs, role2SameAs, selectedBusinessId) {
    // Construct the roles array based on the boolean parameters
    let roles = [mainRole];
    if (role1SameAs === 'Yes') {
        roles.push(role1);
    }
    if (role2SameAs === 'Yes') {
        roles.push(role2);
    }

    if(isBusinessSigner){    
      roles.push('Business Signer');
    }

    VV.Form.Template.AddContact(contactId, selectedContactFirstName, selectedContactLastName, roles, selectedBusinessId, isBusinessSigner);
    clearFieldsCallback();
}

