                    VV.Form.Template.AddLandownerContactModal(
                        recordsArray,
                        addContactInformationCallback,
                        clearFieldsCallback,
                        (searchResults.length <= 25) ? true : false
                    );
                } else {
                    messageData = `No contact records were found for the given search parameters. If you would like to add a new contact, please select 'Add New Contact' button, or click 'Cancel' to refine your search.`;

                    VV.Form.Global.DisplayModal({
                        Icon: "warning",
