                                addressLine1: VV.Form.GetFieldValue("Landowner Search Address Line 1"),
                                addressLine2: VV.Form.GetFieldValue("Landowner Search Address Line 2"),
                                addressLine3: VV.Form.GetFieldValue("Landowner Search Address Line 3"),
                                city: VV.Form.GetFieldValue("Landowner Search City"),
                                provinceState: VV.Form.GetFieldValue("Landowner Search Province State"),
                                county: VV.Form.GetFieldValue("Landowner Search County"),
                                phone: VV.Form.GetFieldValue("Landowner Search Phone"),
                                email: VV.Form.GetFieldValue("Landowner Search Email"),
                            };
                            // Pass the object to the AddLandownerContact function
                            VV.Form.Template.AddLandownerContact(landowner);
                        },
                    });
                }
            } else if (resp.data[0] === "Error") {
                messageData = `An error was encountered. ${resp.data[1]}`;
                displayErrorModal(messageData);
            } else {
                messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
