// RequestWithdrawal for Forest Practices Aerial Chemical Application
const styles = `style="text-align: justify"`;

const oldStatus = VV.Form.GetFieldValue("Status");

// Confirmation function
const doOk = () => {
    Promise.resolve()

        // Create the Status History Record
        .then(() => VV.Form.Template.CreateStatusHistory('Withdrawal Requested', oldStatus))

        // Update fields
        .then(() => Promise.all([
            VV.Form.SetFieldValue("Withdrawal Request Flag", "True"),
            VV.Form.SetFieldValue("Status", "Withdrawal Requested")
        ]))

        // Save the Form
        .then(() => VV.Form.DoAjaxFormSave())

        // Display Success modal
        .then(() => 

            VV.Form.Global.DisplayModal({
                Title: "Success",
                Icon: 'success',
                HtmlContent: `<p ${styles}>Your withdrawal request has been successfully submitted to the region office. A Notice of Decision will be issued following the review of your request.</p>`
            })

        )
        .catch((error) => {
            VV.Form.Global.DisplayModal({
                Title: error.message,
                Icon: 'error',
                HtmlContent: error.messageDetail,
                okFunction,
            });
        });
}

// Confirmation modal
VV.Form.Global.DisplayModal({
    Title: 'Confirmation',
    Icon: 'info',
    HtmlContent: "Do you want to withdrawal your FPA Aerial Chemical application?",
    okFunction: doOk,
    showCancelButton: true
});

