// Function to display the "Select Contact" modal
function showSelectContactModal() {
  const recordHtmlArray = recordsArray
    .map(
      (record) => `
        <tr class="record-row">
          <td>${record["first Name"] || "N/A"}</td>
          <td>${record["last Name"] || "N/A"}</td>
          <td>${record["address Line 1"] || "N/A"}</td>
          <td>${record["city"] || "N/A"}</td>
          <td>${record["state"] == 'Select Item' && !record["province"] ? 'N/A' : record["country"] == "United States" ? record["state"] : record["province"]}</td>
          <td>${record["zip Code"] || "N/A"}</td>
          <td>${record["phone"] || "N/A"}</td>
          <td>
            <button class="k-button add-btn" data-formid="${record["contact Information ID"]}">
              ${addButtonName}
            </button>
          </td>
        </tr>
      `
    )
    .join("");

  const recordHtml = `
    <p>
      ${helpText}
    </p>
    <div class="records-container">
      <table class="record-table">
        <thead>
          <tr>
            <th>First Name</th>
            <th>Last Name</th>
            <th>Address</th>
            <th>City</th>
            <th>State/Province</th>
            <th>Postal/Zip Code</th>
            <th>Phone</th>
            <th></th>
          </tr>
        </thead>
        <tbody>${recordHtmlArray}</tbody>
      </table>
    </div>
  `;

  Swal.fire({
    icon: "info",
    title: `${term} Search`,
    html: recordHtml,
    width: "70rem", // Adjust modal width
    showConfirmButton: addNewContactButton,
    confirmButtonText: 'Add New Contact',
    showCancelButton: true,
    cancelButtonText: "Close Search",
    allowOutsideClick: false,
    didRender: () => {
      // Apply styles after rendering
      $(".records-container").css({
        "max-height": "320px",
        "overflow-y": "auto",
        "overflow-x": "auto",
      });

      $(".record-table").css({
        width: "100%",
        "border-collapse": "collapse",
      });

      $(".record-table th, .record-table td").css({
        padding: "8px",
        "border": "1px solid #333",
        "text-align": "center",
      });

      $(".record-row:nth-child(odd)").css({
        "background-color": "#f9f9f9",
      });

      $(".record-row:nth-child(even)").css({
        "background-color": "white",
      });

      // Add click event to buttons
      $(".add-btn")
        .off("click")
        .on("click", function () {
          const formID = $(this).data("formid");
          const selectedRecord = recordsArray.find(
            (record) => record["contact Information ID"] === formID
          );

          if(businessOrindividual === "Business"){
            showAssociateBusinessModal(selectedRecord); //Go to "Associate Business" modal
          }else{
            showAddContactModal(selectedRecord); // Go to "Add Contact" modal
          }
        });
    },
  }).then((result) => {
    if (result.isDismissed) {
      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    } else if (result.isConfirmed) {
        // Create a new object with the Operator details
        const operator = {
            firstName: VV.Form.GetFieldValue("Operator Search First Name"),
            lastName: VV.Form.GetFieldValue("Operator Search Last Name"),
            country: VV.Form.GetFieldValue("Operator Search Country"),
            postalZipCode: VV.Form.GetFieldValue("Operator Search Postal Zip Code"),
            addressLine1: VV.Form.GetFieldValue("Operator Search Address Line 1"),
            addressLine2: VV.Form.GetFieldValue("Operator Search Address Line 2"),
            addressLine3: VV.Form.GetFieldValue("Operator Search Address Line 3"),
            city: VV.Form.GetFieldValue("Operator Search City"),
            provinceState: VV.Form.GetFieldValue("Operator Search Province State"),
            county: VV.Form.GetFieldValue("Operator Search County"),
            phone: VV.Form.GetFieldValue("Operator Search Phone"),
            email: VV.Form.GetFieldValue("Operator Search Email"),
        };
        // Pass the object to the AddOperatorContact function
        VV.Form.Template.AddOperatorContact(operator);
    }
  });
}

