    VV.Form.SetFieldValue(`${prefix} Country`, "Select Item");
    VV.Form.SetFieldValue(`${prefix} Postal Zip Code`, "");
    VV.Form.SetFieldValue(`${prefix} Address Line 1`, "");
    VV.Form.SetFieldValue(`${prefix} Address Line 2`, "");
    VV.Form.SetFieldValue(`${prefix} Address Line 3`, "");
    VV.Form.SetFieldValue(`${prefix} City`, "");
    VV.Form.SetFieldValue(`${prefix} Province State`, "Select Item");
    VV.Form.SetFieldValue(`${prefix} County`, "Select Item");
    VV.Form.SetFieldValue(`${prefix} Phone`, "");
    VV.Form.SetFieldValue(`${prefix} Email`, "");
    console.log("Search fields cleared.");
}

