// Display error modal
function displayErrorModal(messageData) {
  const unableText = `Unable to add ${label}`;
  let icon = "error";
  if (messageData.includes("Duplicate")) {
    icon = "warning";
    messageData = `Duplicate Found: The selected ${label} is already associated with this application.`;
  }
  VV.Form.Global.DisplayModal({
    Title: unableText,
    Icon: icon,
    HtmlContent: messageData,
  });
}

// QuestionDropDownChange for Forest Practices Aerial Chemical Application Notification
const selectedQuestion = VV.Form.GetDropDownListItemValue('List Of Questions');
if (selectedQuestion == 'Select Item') return;

const QUESTIONS = VV.Form.Template.GetNavigationMap();
const currentQuestionID = VV.Form.GetFieldValue('Current Screen');
const currentQuestion = QUESTIONS[currentQuestionID];
const currentQuestionText = `${currentQuestionID}. ${currentQuestion.text}`;

if (selectedQuestion == currentQuestionText) return;

const [targetQuestionID, targetQuestion] = Object.entries(QUESTIONS).find(
  ([key, value]) => `${key}. ${value.text}` === selectedQuestion
);

if (!targetQuestionID) return;

VV.Form.Global.DisplayModal({
  Title: 'Confirm',
  Icon: 'warning',
  ConfirmText: 'Confirm',
  HtmlContent: `You chose to navigate to question number ${targetQuestionID}. Please click Confirm to navigate to that question, or Cancel to stay on the current question.`,
  okFunction: function () {
    VV.Form.SetFieldValue('Current Screen', targetQuestionID).then(() =>
      VV.Form.Template.HandleNavigation('Set')
    );
  },
  cancelFunction: function () {
    const currentDropdownVal = `${currentQuestionID}. ${currentQuestion.text}`;
    VV.Form.SetFieldValue('List Of Questions', currentDropdownVal);
  },
});

