// AddressFieldNamesMap for Forest Practices Application/Notification

/*
  This function returns an address object with field names mapped to the appropriate field names for the form.

  Function name: AddressFieldNamesMap

  Parameter:
  - addressType: a string specifying the address set to map field names for (e.g. "mailingAddress", "physicalAddress").
  - hasCountry: a boolean specifying whether the address has a country field or not.
*/

const landOwnerInformationMailingAddressMap = new Map([
    ['street1', 'Address Line 1 Landowner'],
    ['city', 'City Landowner'],
    ['state', 'State Landowner'],
    ['zipCode', 'Zip Code Landowner'],
    ['country', 'Country Landowner'],
    ['county', 'County Landowner'],
]);

const timberOwnerInformationMailingAddressMap = new Map([
    ['street1', 'Address Line 1 Timber Owner'],
    ['city', 'City Timber Owner'],
    ['state', 'State Timber Owner'],
    ['zipCode', 'Zip Code Timber Owner'],
    ['country', 'Country Timber Owner'],
    ['county', 'County Timber Owner'],
]);

const operatorInformationMailingAddressMap = new Map([
    ['street1', 'Address Line 1 Operator'],
    ['city', 'City Operator'],
    ['state', 'State Operator'],
    ['zipCode', 'Zip Code Operator'],
    ['country', 'Country Operator'],
    ['county', 'County Operator'],
]);

let addressFieldNamesMap;
switch (addressType) {
    case 'landOwnerInformationAddress':
        addressFieldNamesMap = landOwnerInformationMailingAddressMap;
        break;
    case 'timberOwnerInformationAddress':
        addressFieldNamesMap = timberOwnerInformationMailingAddressMap;
        break;
    case 'operatorInformationAddress':
        addressFieldNamesMap = operatorInformationMailingAddressMap;
        break;
    default:
        throw new Error('Invalid address type specified.');
}

const address = {};
for (const [key, value] of addressFieldNamesMap) {
    address[key] = value;
}

if (hasCountry) {
    address.hasCountry = true;
} else {
    address.hasCountry = false;
}

return address;

