/*
    Function Name: Form_onLoad - FPA Aerial Chemical Application
    Customer:      Washington DNR
    Purpose:       This function initializes the FPA Aerial Chemical Application form.
                   It registers all DataGrids, ensures that the form instance is persisted
                   on first load, updates the browser URL to reference the saved record,
                   and sets up user roles, navigation, and document paths.

    Parameters:    None

    Date of Dev:   --/--/----
    Last Rev Date: 10/28/2025

    --/--/---- - Previous contributors: Initial revision
    10/28/2025 - Matias Andrade: Added early form persistence and browser URL update logic to ensure the saved record reloads correctly after refresh.
    01/26/2026 - Zharich Barona: Added logic to handle view-only roles to determine if the form needs to be saved on load or not.
*/

try {
  // Register DataGrids for the current form
  VV.Form.Global.RegisterDatagrids([
    'DG Landowner Businesses',
    'DG Landowners',
    'DG Timber Owners',
    'DG Timber Owner Businesses',
    'DG Operators',
    'DG Operator Businesses',
    'DG Chemical Information',
    'DG Legal Description',
    'DG Signatures',
    'DG Landowner Businesses Signer',
    'DG Timber Owner Businesses Signer',
    'DG Operator Businesses Signer',
  ]);
} catch (error) {
  console.error('Error registering datagrids:', error);
}

// Get roles directly (synchronous)
const currentRolesGlobal = VV.Form.Global.GetCurrentRoles();
const ONLY_VIEW_ROLES = ['field', 'management', 'internal'];
const isViewRole = currentRolesGlobal.some((role) => ONLY_VIEW_ROLES.some((key) => role.toString().toLowerCase().includes(key)));
const isSignatory = currentRolesGlobal.some((role) => role === 'signatory');

if (isSignatory) {
  VV.Form.Global.SignatoryDisableButtonByFieldName('btnUpload');
}

// Initialize variables
let rolesCache = [];

if (isViewRole) {

  rolesCache = VV.Form.Global.GetCurrentRoles();
  // Set UserRoles field
  VV.Form.SetFieldValue('UserRoles', rolesCache.join('|'));

  // Process all role flags
  const isOfficeStaff = rolesCache.some(
    (role) =>
      role.toString().toLowerCase() === 'office staff' ||
      role.toString().toLowerCase() === 'vaultaccess'
  );
  VV.Form.SetFieldValue('IsOfficeStaff', isOfficeStaff, true);

  const isProponent = rolesCache.some((role) => role.toString().toLowerCase() === 'proponent');
  VV.Form.SetFieldValue('isProponent', isProponent, true);

  const isFieldStaff = rolesCache.some((role) => role.toString().toLowerCase() === 'field staff');
  VV.Form.SetFieldValue('isFieldStaff', isFieldStaff, true);  

}else {
  // Main execution chain - handle roles and sequential operations
  VV.Form.DoAjaxFormSave()
    .then(() =>
      VV.Form.GetFieldValue('Status') === undefined || VV.Form.GetFieldValue('Status') === ''
        ? VV.Form.SetFieldValue('Status', 'Draft')
        : Promise.resolve()
    )
    .then(() => {
      try {
        VV.Form.Global.UpdateWindowLocationURL();
      } catch (urlErr) {
        console.error('Error updating URL after first save:', urlErr);
      }
      return Promise.all([VV.Form.Global.GetCurrentRoles(), VV.Form.GetFieldValue('UserRoles')]);
    })
    .then(([roles, currentRoles]) => {
      rolesCache = roles;

      // Set UserRoles field
      VV.Form.SetFieldValue('UserRoles', rolesCache.join('|'));

      // Process all role flags
      const isOfficeStaff = rolesCache.some(
        (role) =>
          role.toString().toLowerCase() === 'office staff' ||
          role.toString().toLowerCase() === 'vaultaccess'
      );

      return VV.Form.SetFieldValue('IsOfficeStaff', isOfficeStaff, true)
        .then(() => {
          if (isOfficeStaff) {
            return VV.Form.SetFieldValue('Created By Office Staff', true, true);
          }
        })
        .then(() => {
          // Pass updatedRoles forward to next .then
          return rolesCache;
        });
    })
    .then(() => {
      // Process all role flags
      const isOfficeStaff = rolesCache.some(
        (role) =>
          role.toString().toLowerCase() === 'office staff' ||
          role.toString().toLowerCase() === 'vaultaccess'
      );
      VV.Form.SetFieldValue('IsOfficeStaff', isOfficeStaff, true);

      const isProponent = rolesCache.some((role) => role.toString().toLowerCase() === 'proponent');
      VV.Form.SetFieldValue('isProponent', isProponent, true);

      const isFieldStaff = rolesCache.some((role) => role.toString().toLowerCase() === 'field staff');
      VV.Form.SetFieldValue('isFieldStaff', isFieldStaff, true);

      const status = VV.Form.GetFieldValue('Status');
      if (isProponent && !['draft', 'pending revisions'].includes(status.toLowerCase())) {
        VV.Form.SetFieldValue('Show All Questions CheckBox', 'True');
      }

      // Check if SetIndividual is needed based on specific conditions
      const IndividualIdPresent = VV.Form.GetFieldValue('Individual ID') !== '';
      const UserIdPresent = VV.Form.GetFieldValue('UserID') !== '';

      const needsSetIndividual = isProponent && (!IndividualIdPresent || !UserIdPresent);

      return needsSetIndividual;
    })
    .then((needsSetIndividual) => {
      // Execute SetIndividual if needed and wait for completion
      if (needsSetIndividual) {
        return VV.Form.Template.SetIndividual();
      }
      return Promise.resolve();
    })
    .then(() => {
      // Handle navigation after SetIndividual completes
      return VV.Form.Template.HandleNavigation('Set');
    })
    .then(() => {
      // Update document path after navigation is handled
      return VV.Form.Template.UpdateDocumentPath();
    })
    .then(() => {
      // Load activity map as final step before save
      return VV.Form.Template.LoadActivityMap();
    })
    .then(() => {
      // Save form at the very end
      return VV.Form.DoAjaxFormSave();
    })
    .catch((error) => {
      console.error('Error in sequential execution:', error);

      // Even if something fails, still try to set essential elements
      try {
        VV.Form.Template.HandleNavigation('Set');
      } catch (navError) {
        console.error('Error handling navigation in catch:', navError);
      }

      try {
        VV.Form.Template.UpdateDocumentPath();
      } catch (docError) {
        console.error('Error setting document upload path in catch:', docError);
      }

      try {
        VV.Form.Template.LoadActivityMap();
      } catch (mapError) {
        console.error('Error loading activity map in catch:', mapError);
      }
    });
}

