      The system will show any matching business. If the business you’re looking for is not found, you will be given the option to add a new business as a timber owner.
    </p>
  </div>
`;

VV.Form.Global.CentralMessages("Help", {
  helpTitle: "1b Business Search",
  helpText: modalContent,
});

function submit() {
  //btnSubmit_onClick.js for FPA ACA
  const isOfficeStaff = VV.Form.GetFieldValue("IsOfficeStaff") === "True";
  if (isOfficeStaff && !VV.Form.Template.FormValidation("Region")) {
    VV.Form.Global.ValidationModal();
    return;
  }

  // Get FPAN Number
  const fpanNumber = VV.Form.GetFieldValue("FPAN Number");

  // If FPAN Number is not set, create the ARP, else update existed ARP
  if (fpanNumber === "") {
    VV.Form.DoAjaxFormSave().then(() => {
      VV.Form.Template.CreateApplicationReviewPage();
    });
  } else {
    VV.Form.Global.SubmitApplicationUpdate();
  }
}

VV.Form.Global.DisplayModal({
  HtmlContent:
    "<p>Do you want to submit your FPA Aerial Chemical application?</p>",
  Icon: "question",
  okFunction: submit,
  Title: "Confirmation",
});

const currentStatus = VV.Form.GetFieldValue("Status");

if (currentStatus != "Draft") {
  VV.Form.Template.RequestWithdrawal();
}

