/*
  Function Name: btnActivtyMap
  Customer:      Washington DNR
  Purpose:       The purpose of this btn is to display the activity map in a swal modal.
  Parameters:    event, control
  Date of Dev:   12/23/2024
  Last Rev Date: 12/22/2025
  12/23/2024 - Ross Rhone: Created activity map btn.
  01/14/2025 - Austin Stone: Moved map over to subform, activity map btn now opens subform
  05/23/2025 - Ross: Created global functions so the activity button can be opened directly from the form
  12/22/2025 - Santiago Tortu: Corrected Activity Map button to call VV.Form.Global.OpenGISModal instead of Form.Global.OpenGISModal
  03/12/2026 - Ross Rhone: Updated to call the GIS_onLoad function which checks if the GIS map is loaded before attempting to 
               open the modal and to handle cases where the GIS map fails to load.

*/

VV.Form.Global.GIS_onLoad(event)
  .then(function () {
    if (VV.Form.Global.IsMapLoaded()) {
      VV.Form.Global.OpenGISModal(VV.Form.GetFieldValue("Top Form ID"));
    }
  })
  .catch(function (err) {
    console.error("btnActivityMap_onClick: GIS failed to load.", err);
  });

//Dont show modal for signatory as this check is done automatically to show the entire app
const roles = VV.Form.Global.GetCurrentRoles();

const lowerRoles = roles.map((role) => role.toLowerCase());
  const isSignatory = lowerRoles.includes('signatory');
  const isProponent = lowerRoles.includes('proponent');
  const status = VV.Form.GetFieldValue('Status');
  if (
    isSignatory ||
    (isProponent && !['draft', 'pending revisions'].includes(status.toLowerCase()))
  ) {
    return;
  }

